sys_variable_value.value:
(function execute(inputs, outputs) {
     gs.error('FLOW EXECUTION TEST — Script Step is running');
    var discord = new discordNotification();

    if (!inputs.reserved_for) {
        gs.error('reserved_for input is undefined');
        return;
    }

    if (!inputs.workspace) {
        gs.error('workspace input is undefined');
        return;
    }
    // var name = inputs.reserved_for.getValue("name");
    var name = inputs.reserved_for.toString() ? inputs.reserved_for.getValue("name") : "undefined";
    var workspace = inputs.workspace.getDisplayValue();
    //var date = inputs.start_date_time.getDisplayValue();
    
    // var gdt = new GlideDateTime(inputs.start_date_time.toString());
    // var jsDate = new Date(gdt.getNumericValue());
    // var date = jsDate.toLocaleString();

    // var gdt = new GlideDateTime(inputs.start_date_time);
    // var date = gdt.getByFormat("MM-dd-yyyy hh:mm a"); // "12-07-2026 6:15 PM"

    // var gdt = new GlideDateTime(inputs.start_date_time);
    // // Extract the local time object from GlideDateTime
    // var localTime = gdt.getLocalTime();     
    // // GlideTime explicitly supports getByFormat() 
    // var timeString = localTime.getByFormat("hh:mm a");     
    // // Removes leading zero if the hour is single digit (e.g., "04:00 PM" -> "4:00 PM")
    // var date = timeString.replace(/^0/, ''); 

    // var d = inputs.start_date_time;
    
   
    // var gdt = new GlideDateTime();
    // gdt.setValue(inputs.start_date_time + '');

    // // 'getByFormat' is natively supported in Flow Designer scripts
    // // Pattern: MMMM (Full Month), dd (Day), yyyy (Year), hh:mm (12-hr), a (AM/PM)
    // var date = gdt.getByFormat("MMMM-dd-yyyy h:mm a");

    // // 1. Initialize your timestamp object
    // var gdt = new GlideDateTime();
    // gdt.setValue(inputs.start_date_time + '');

    // // 2. Extract the local Date and Time sub-objects
    // var localDate = gdt.getLocalDate(); // Gets a GlideDate object in local timezone
    // var localTime = gdt.getTime();      // Gets a GlideTime object in local timezone

    // // 3. Apply getByFormat to the sub-objects safely
    // var datePart = localDate.getByFormat("MMMM-dd-yyyy"); // E.g., "July-14-2026"
    // var timePart = localTime.getByFormat("h:mm a");       // E.g., "1:59 AM" (12-hour clock)

    // // 4. Stitch them together for your final output string
    // var date = datePart + " " + timePart;



    // // 1. Get the raw text representation directly from the catalog item pill
    // var rawString = inputs.start_date_time + ''; // Format: "YYYY-MM-DD HH:mm:ss"

    // // Define a default fallback string
    // var date = "No Date Selected";

    // if (rawString && rawString.indexOf('-') > -1) {
    //     // 2. Split the string into pieces: [ "YYYY", "MM", "DD HH:mm:ss" ]
    //     var parts = rawString.split('-');
    //     var year = parts[0];
    //     var monthNum = parseInt(parts[1], 10);
        
    //     // Split the space between the day and the time: [ "DD", "HH:mm:ss" ]
    //     var dayTimeParts = parts[2].split(' ');
    //     var day = dayTimeParts[0];
        
    //     // Split the time: [ "HH", "mm", "ss" ]
    //     var timeParts = dayTimeParts[1].split(':');
    //     var hour = parseInt(timeParts[0], 10);
    //     var minute = timeParts[1];

    //     // 3. Map the month number to the full text name
    //     var monthNames = ["January", "February", "March", "April", "May", "June", 
    //                     "July", "August", "September", "October", "November", "December"];
    //     var monthName = monthNames[monthNum - 1];

    //     // 4. Calculate 12-hour AM/PM from the raw database hour digit
    //     var ampm = hour >= 12 ? 'PM' : 'AM';
    //     hour = hour % 12;
    //     hour = hour ? hour : 12; // If hour is 0, make it 12

    //     // 5. Build your exact target string structure
    //     date = monthName + "-" + day + "-" + year + " " + hour + ":" + minute + " " + ampm;
    // }

    
    // 1. Pass the database date pill into GlideDateTime to initialize it
    var gdt = new GlideDateTime(inputs.start_date_time);

    // 2. Extract the raw numerical epoch milliseconds (this is timezone-neutral)
    var ms = gdt.getNumericValue();

    // 3. Drop it into a standard JavaScript Date object (automatically shifts back to Local Time)
    var jsDate = new Date(ms);

    var date = "No Date Selected";

    if (jsDate) {
        // 4. Extract individual time parts based on your instance's regional clock settings
        var year = jsDate.getFullYear();
        var day = jsDate.getDate();
        var monthNum = jsDate.getMonth(); // Note: JS months are naturally 0-indexed (0 = January)
        
        var hour = jsDate.getHours();
        var minute = jsDate.getMinutes();
        
        // Add a leading zero to minutes if they are single digits (e.g., 9 -> "09")
        if (minute < 10) { minute = "0" + minute; }

        // 5. Array map to assign the textual month name
        var monthNames = ["January", "February", "March", "April", "May", "June", 
                        "July", "August", "September", "October", "November", "December"];
        var monthName = monthNames[monthNum];

        // 6. Calculate 12-hour AM/PM structure
        var ampm = hour >= 12 ? 'PM' : 'AM';
        hour = hour % 12;
        hour = hour ? hour : 12; // If hour is 0, make it 12

        // 7. Format into your target layout: MONTH-Day-YEAR 8:00 PM
        date = monthName + "-" + day + "-" + year + " " + hour + ":" + minute + " " + ampm;
    }

    var msg = name + ' has been approved for workspace ' + workspace +
            ' starting at ' + date + '.';
    gs.info('Discord MSG (Flow Execution): ' + msg); //This shows up in Flow Execution Details.
    discord.sendMessage(msg, ':white_check_mark:');

})(inputs, outputs);

